example.code:
- name: Install Poetry uses: snok/install-poetry@v1 with: version: 1.8.5 virtualenvs-create: true virtualenvs-in-project: true
- name: Load cached venv uses: actions/cache@v4 with: path: .venv key: venv-${{ runner.os }}-${{ matrix.python-version }}-${{ hashFiles('**/poetry.lock') }}
- name: Install dependencies run: poetry install --no-interaction --sync
